fn test_ilog_monotonic() {
        let mut prev = ilog_to_linear(0.0);
        for i in 1..=100 {
            let x = i as f32 / 100.0;
            let lin = ilog_to_linear(x);
            assert!(lin >= prev, "Non-monotonic at x={x}: {lin} < {prev}");
            prev = lin;
        }
